def _history_with_acks(events: list) -> list:
    """Annotate history events with ack status for API responses."""
    with _alert_acks_lock:
        acked = dict(_alert_acks)
    out = []
    for ev in events:
        e = dict(ev)
        aid = e.get("id", "")
        if aid and aid in acked:
            e["acked"] = acked[aid]
        else:
            e["acked"] = None
        out.append(e)
    return out


