# ─── Hub API routes (active when mode == hub or both) ────────────────────────

@app.post(f"/api/{HUB_API_VERSION}/heartbeat")
def hub_heartbeat():
    cfg    = monitor.app_cfg
    secret = cfg.hub.secret_key
    if cfg.hub.mode not in ("hub","both"):
        return jsonify({"error":"not a hub"}), 404

    # ── Rate limiting ─────────────────────────────────────────────────────────
    # Key by X-Forwarded-For if set (reverse proxy), else remote_addr
    # Site name extracted post-decryption for accurate per-site limiting
    forwarded = request.headers.get("X-Forwarded-For", "")
    client_ip = forwarded.split(",")[0].strip() if forwarded else (request.remote_addr or "")

    # ── Read raw body (may be encrypted) ─────────────────────────────────────
    raw_body = request.get_data()

    # ── Signature + timestamp verification (if secret configured) ────────────
    if secret:
        sig   = request.headers.get("X-Hub-Sig","")
        ts_h  = request.headers.get("X-Hub-Ts","0")
        nonce = request.headers.get("X-Hub-Nonce","")

        if not sig or not nonce:
            return jsonify({"error":"missing security headers"}), 403

        try:
            ts = float(ts_h)
        except ValueError:
            return jsonify({"error":"invalid timestamp"}), 403

        # Replay check
        if not hub_nonce_store.check_and_store(nonce):
            return jsonify({"error":"replay detected"}), 403

        # Decrypt if Content-Type says octet-stream
        ct = request.content_type or ""
        if "octet-stream" in ct:
            try:
                raw_body = hub_decrypt_payload(secret, raw_body)
            except Exception as e:
                return jsonify({"error":f"decryption failed: {e}"}), 403

        # Verify HMAC over decrypted body
        ok, reason = hub_verify_signature(secret, raw_body, sig, ts)
        if not ok:
            print(f"[HubSec] Signature rejected from {client_ip}: {reason}")
            return jsonify({"error":"forbidden","reason":reason}), 403

    # ── Parse JSON payload ────────────────────────────────────────────────────
    try:
        payload = json.loads(raw_body) if raw_body else {}
    except Exception:
        return jsonify({"error":"bad json"}), 400

    # ── Rate limiting — keyed by site name for accuracy across NAT ───────────
    # Use site name from payload (more reliable than IP when clients share NAT)
    site_key = payload.get("site", "") or client_ip
    if not hub_rate_limiter.allow(site_key):
        return jsonify({"error":"rate limit exceeded"}), 429

    # ── Ingest ────────────────────────────────────────────────────────────────
    hub_server.set_secret(secret)
    ingest_status = hub_server.ingest(payload, client_ip=client_ip)

    site_name = payload.get("site","")

    # Pending approval — acknowledge receipt but send no commands
    if ingest_status == "pending":
        ack = {"ok": True, "status": "pending_approval",
               "message": "This site is awaiting approval on the hub dashboard."}
        ack_bytes = json.dumps(ack).encode()
        if secret:
            enc = hub_encrypt_payload(secret, ack_bytes)
            return Response(enc, content_type="application/octet-stream")
        return jsonify(ack)

    # ── Build ACK — encrypt if secret is set ─────────────────────────────────
    listen_reqs   = listen_registry.pending_for_site(site_name)
    relay_bitrate = hub_server.get_relay_bitrate(site_name)
    pending_cmd   = hub_server.pop_pending_command(site_name)   # dict or None
    ack = {"ok": True, "listen_requests": listen_reqs, "relay_bitrate": relay_bitrate}
    if pending_cmd:
        ack["command"] = pending_cmd  # structured dict: {"type": ..., "payload": {...}}
    ack_bytes = json.dumps(ack).encode()

    if secret:
        enc = hub_encrypt_payload(secret, ack_bytes)
        return Response(enc, content_type="application/octet-stream")
    return jsonify(ack)

@app.post("/hub/clip_upload")
def hub_clip_upload():
    """Receive a WAV clip (base64) uploaded from a client after a chain fault.

    The clip is saved into alert_snippets/<site>_<stream>/ on the hub so it
    appears in the hub's Reports page alongside the chain fault event.
    """
    cfg    = monitor.app_cfg
    secret = cfg.hub.secret_key
    if cfg.hub.mode not in ("hub", "both"):
        return jsonify({"error": "not a hub"}), 404

    raw_body = request.get_data()
    if secret:
        sig  = request.headers.get("X-Hub-Sig", "")
        ts_h = request.headers.get("X-Hub-Ts", "0")
        try:
            ts = float(ts_h)
        except ValueError:
            return jsonify({"error": "invalid timestamp"}), 403
        ct = request.content_type or ""
        if "octet-stream" in ct:
            try:
                raw_body = hub_decrypt_payload(secret, raw_body)
            except Exception as e:
                return jsonify({"error": f"decryption failed: {e}"}), 403
        ok, reason = hub_verify_signature(secret, raw_body, sig, ts)
        if not ok:
            return jsonify({"error": "forbidden", "reason": reason}), 403

    try:
        data = json.loads(raw_body)
    except Exception:
        return jsonify({"error": "bad json"}), 400

    site       = str(data.get("site",       "unknown")).strip()
    stream     = str(data.get("stream",     "unknown")).strip()
    label      = str(data.get("label",      "clip")).strip()
    chain_name = str(data.get("chain_name", "")).strip()
    chain_id   = str(data.get("chain_id",   "")).strip()
    data_b64   = data.get("data_b64", "")

    if not data_b64:
        return jsonify({"error": "no clip data"}), 400
    try:
        wav_bytes = base64.b64decode(data_b64)
    except Exception:
        return jsonify({"error": "bad base64"}), 400

    # Save under alert_snippets/<site>_<stream>/ on the hub
    safe_key = f"{_safe_name(site)}_{_safe_name(stream)}"
    out_dir  = os.path.join(BASE_DIR, "alert_snippets", safe_key)
    os.makedirs(out_dir, exist_ok=True)
    fname = f"{label}_{int(time.time())}.wav"
    fpath = os.path.join(out_dir, fname)
    with open(fpath, "wb") as f:
        f.write(wav_bytes)

    # Write to hub alert log so it appears on the Reports page
    _alert_log_append({
        "id":            str(uuid.uuid4()),
        "ts":            time.strftime("%Y-%m-%d %H:%M:%S"),
        "stream":        f"{site} / {stream}",
        "type":          "CHAIN_FAULT",
        "message":       (f"Remote clip from '{site}' — '{stream}'"
                          + (f" (chain: {chain_name})" if chain_name else "") + "."),
        "level_dbfs":    None,
        "rtp_loss_pct":  None,
        "rtp_jitter_ms": None,
        "clip":          fname,
        "ptp_state":     "",
        "ptp_offset_us": 0,
        "ptp_drift_us":  0,
        "ptp_jitter_us": 0,
        "ptp_gm":        "",
    })
    # Link clip back to the most recent fault log entry for this chain
    if chain_id:
        _clip_label = "last_good" if "last_good" in label else "fault"
        flog = hub_server._chain_fault_log.get(chain_id, [])
        if flog:
            clips = flog[-1].setdefault("clips", [])
            clips.append({"key": safe_key, "fname": fname, "label": _clip_label})
            metrics_db.fault_log_update_clips(flog[-1].get("id", ""), clips)

    monitor.log(f"[Hub] Clip upload received: {site}/{stream}/{label} "
                f"({len(wav_bytes) // 1024}KB → {fname})")
    return jsonify({"ok": True, "saved": fname})


@app.post("/hub/backup_upload")
def hub_backup_upload():
    """Receive a full backup ZIP uploaded from a client site.

    The client POSTs raw ZIP bytes with X-Hub-Sig / X-Hub-Ts HMAC headers.
    The site name is identified via the X-Hub-Site header (or falls back to the
    'site' field in the payload, but since this is binary ZIP we use the header).
    The hub writes the latest backup to HUB_BACKUP_DIR/<site>/backup.zip and
    exposes it via GET /api/hub/site/<name>/backup for download.
    """
    cfg    = monitor.app_cfg
    secret = cfg.hub.secret_key
    if cfg.hub.mode not in ("hub", "both"):
        return jsonify({"error": "not a hub"}), 404

    raw_body = request.get_data()
    site_name = request.headers.get("X-Hub-Site", "").strip()

    if secret:
        sig  = request.headers.get("X-Hub-Sig", "")
        ts_h = request.headers.get("X-Hub-Ts", "0")
        try:
            ts = float(ts_h)
        except ValueError:
            return jsonify({"error": "invalid timestamp"}), 403
        ok, reason = hub_verify_signature(secret, raw_body, sig, ts)
        if not ok:
            return jsonify({"error": "forbidden", "reason": reason}), 403

    if not site_name:
        return jsonify({"error": "missing X-Hub-Site header"}), 400

    # Cap per-site backup at 200 MB
    MAX_BACKUP_BYTES = 200 * 1024 * 1024
    if len(raw_body) > MAX_BACKUP_BYTES:
        return jsonify({"error": "backup too large (>200 MB)"}), 413

    hub_server.set_secret(secret)
    hub_server.save_backup_to_disk(site_name, raw_body)
    return jsonify({"ok": True})


@app.post("/hub/ping_result")
def hub_ping_result():
    """Receive a ping/connectivity test result uploaded from a client site."""
    cfg    = monitor.app_cfg
    secret = cfg.hub.secret_key
    if cfg.hub.mode not in ("hub", "both"):
        return jsonify({"error": "not a hub"}), 404

    raw_body = request.get_data()
    if secret:
        sig  = request.headers.get("X-Hub-Sig", "")
        ts_h = request.headers.get("X-Hub-Ts", "0")
        try:
            ts = float(ts_h)
        except ValueError:
            return jsonify({"error": "invalid timestamp"}), 403
        ct = request.content_type or ""
        if "octet-stream" in ct:
            try:
                raw_body = hub_decrypt_payload(secret, raw_body)
            except Exception as e:
                return jsonify({"error": f"decryption failed: {e}"}), 403
        ok, reason = hub_verify_signature(secret, raw_body, sig, ts)
        if not ok:
            return jsonify({"error": "forbidden", "reason": reason}), 403

    try:
        data = json.loads(raw_body)
    except Exception:
        return jsonify({"error": "bad json"}), 400

    site_name = str(data.get("site", "")).strip()
    if not site_name:
        site_name = request.headers.get("X-Hub-Site", "unknown").strip()

    hub_server.set_secret(secret)
    with hub_server._lock:
        hub_server._ping_results[site_name] = {
            "target":  str(data.get("target",  "")).strip(),
            "output":  str(data.get("output",  ""))[:2000],
            "success": bool(data.get("success", False)),
            "ts":      float(data.get("ts", time.time())),
        }
    monitor.log(f"[Hub] Ping result from '{site_name}': target={data.get('target','')} "
                f"success={data.get('success',False)}")
    return jsonify({"ok": True})


@app.get("/hub/update/download")
def hub_update_download():
    """Serve the hub's own signalscope.py to authenticated clients for self-update.

    The request must carry valid HMAC headers (same scheme as heartbeats) so only
    clients with the correct shared secret can download the file.  No login cookie
    is required — the client daemon uses HMAC, not a browser session.
    """
    cfg    = monitor.app_cfg
    secret = cfg.hub.secret_key
    if cfg.hub.mode not in ("hub", "both"):
        return jsonify({"error": "not a hub"}), 404

    # Auth — HMAC over an empty body for this GET request
    if secret:
        sig   = request.headers.get("X-Hub-Sig",   "")
        ts_h  = request.headers.get("X-Hub-Ts",    "0")
        nonce = request.headers.get("X-Hub-Nonce", "")
        try:
            ts = float(ts_h)
        except ValueError:
            return jsonify({"error": "invalid timestamp"}), 403
        if not hub_nonce_store.check_and_store(nonce):
            return jsonify({"error": "replay detected"}), 403
        ok, reason = hub_verify_signature(secret, b"", sig, ts)
        if not ok:
            return jsonify({"error": "forbidden", "reason": reason}), 403

    script_path = os.path.abspath(__file__)
    return send_from_directory(
        os.path.dirname(script_path),
        os.path.basename(script_path),
        as_attachment=True,
        download_name="signalscope.py",
        mimetype="text/plain",
    )


